SELECT
    a.*,
    b.index_name AS kemu_value,
    c.exam_paper_name,
    c.exam_paper_myscore AS exam_paper_score,
    d.real_name AS teacher_name
FROM exam_info a
LEFT JOIN dictionary b ON a.kemu_types = b.code_index AND b.dic_code = 'kemu_types'
LEFT JOIN exam_paper c ON a.exam_paper_id = c.id
LEFT JOIN teachers d ON a.teacher_id = d.id



        AND a.exam_name LIKE CONCAT('%', #{req.examName}, '%')




        AND a.kemu_types = #{req.kemuTypes}




        AND a.status = #{req.status}




        AND (
            a.teacher_id = #{req.teacherId}
            OR a.kemu_types = (
                SELECT kemu_types FROM teachers WHERE id = #{req.teacherId}
            )
        )


ORDER BY a.create_time DESC
